import React, { useEffect, useState } from 'react';
import { MDBDataTableV5 } from 'mdbreact';
import { Button, Badge } from 'reactstrap'
import moment from 'moment'

const statusBadgeColor = status => {
  switch (status) {
    case 'sent': return 'success'
    case 'sending': return 'info'
    case 'draft': return 'secondary'
    default: return 'secondary'
  }
}

const CampaignTable = props => {

  const [dataColumns] = useState([
    {
      label: 'Name',
      field: 'name',
      width: 150,
    },
    {
      label: 'Segment',
      field: 'segment',
      width: 100,
    },
    {
      label: 'Number of contacts',
      field: 'numOfContacts',
      width: 270,
    },
    {
      label: 'Status',
      field: 'status',
      width: 270,
    },
    {
      label: 'Created at',
      field: 'createdAt',
      width: 270,
    },
    {
      label: '',
      field: 'details',
      sort: 'disabled',
      width: 200,
    }
  ])

  const [dataRows, setDataRows] = useState([])

  useEffect(() => {
    const getRows = () => {
      return props.campaigns.map(campaign => {
        return {
          name: campaign.name,
          segment: campaign.segment.name,
          numOfContacts: campaign.num_of_contacts,
          status: (
            <Badge color={statusBadgeColor(campaign.status)} pill>
              {campaign.status.replace(/^\w/, c => c.toUpperCase())}
            </Badge>
          ),
          createdAt: moment(campaign.created_at).format('lll'),
          details: <Button color="info" href={`/campaigns/${campaign.id}`}>Details</Button>
        }
      })
    }
    setDataRows(getRows())
  }, [props.campaigns])

  return (
    <div className="main">
      <MDBDataTableV5
        hover
        data={{ columns: dataColumns, rows: dataRows }}
        fixed
        pagingTop
        searchTop
        searchBottom={false}
      />
    </div>
  )
}

export default CampaignTable
